import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", desc: "Building high-performance, responsive websites with React.", color: "#0d6efd" },
    { id: 2, title: "UI/UX Design", icon: "fas fa-paint-brush", desc: "User-centric design with modern aesthetics and research.", color: "#dc3545" },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", desc: "Cross-platform mobile apps for iOS and Android.", color: "#198754" },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-open", desc: "Comprehensive technical help for academic excellence.", color: "#ffc107" },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", desc: "Striking presentations that tell your story effectively.", color: "#0dcaf0" },
    { id: 6, title: "Report Writing", icon: "fas fa-file-alt", desc: "Detailed technical documentation and business reports.", color: "#6c757d" },
    { id: 7, title: "Digital Marketing", icon: "fas fa-bullhorn", desc: "Expanding your digital reach with targeted strategies.", color: "#343a40" },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-nib", desc: "SEO-friendly, engaging content for your target audience.", color: "#0d6efd" },
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-plus", desc: "Rank higher on search engines and attract traffic.", color: "#0dcaf0" }
  ];

  return (
    <div className="services-section py-5">
      <div className="container py-5">
        
        {/* Modern Header */}
        <div className="text-center mb-5 pb-3">
          <h2 className="fw-bold display-5 mb-2 gradient-text">Modern Solutions</h2>
          <p className="text-muted fs-5">Elevating your business with premium digital services.</p>
          <div className="header-line mx-auto"></div>
        </div>

        <div className="row g-5">
          {serviceData.map((service) => (
            <div className="col-lg-4 col-md-6" key={service.id}>
              <div className="modern-card">
                {/* Colored Accent Line */}
                <div className="accent-line" style={{ backgroundColor: service.color }}></div>
                
                {/* Floating Icon Box */}
                <div className="icon-container shadow-lg" style={{ color: service.color, border: `1px solid ${service.color}30` }}>
                  <i className={service.icon}></i>
                </div>

                <div className="card-content text-center">
                  <h4 className="fw-bold mb-3">{service.title}</h4>
                  <p className="text-muted small mb-4">{service.desc}</p>
                  
                  <Link to="/register" className="btn-modern shadow-sm" style={{ '--hover-color': service.color }}>
                    Choose Plan <i className="fas fa-arrow-right ms-2"></i>
                  </Link>
                </div>

                {/* Glassy Overlay Decoration */}
                <div className="glass-blob" style={{ backgroundColor: `${service.color}10` }}></div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* --- PREMIMUM CSS (He copy kar) --- */}
      <style>{`
        .services-section { background-color: #fcfdfe; }
        
        .gradient-text {
          background: linear-gradient(90deg, #1e3c72, #2a5298);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }

        .header-line {
          width: 50px;
          height: 5px;
          background: #0d6efd;
          border-radius: 10px;
        }

        .modern-card {
          position: relative;
          background: #ffffff;
          border-radius: 25px;
          padding: 50px 30px 40px;
          transition: all 0.4s ease;
          border: 1px solid #f0f0f0;
          height: 100%;
          z-index: 1;
        }

        .accent-line {
          position: absolute;
          top: 0;
          left: 50%;
          transform: translateX(-50%);
          width: 60px;
          height: 6px;
          border-radius: 0 0 10px 10px;
          transition: width 0.3s ease;
        }

        .icon-container {
          position: absolute;
          top: -35px;
          left: 50%;
          transform: translateX(-50%);
          width: 75px;
          height: 75px;
          background: #ffffff;
          border-radius: 20px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 1.8rem;
          transition: 0.4s ease;
        }

        .modern-card:hover {
          transform: translateY(-15px);
          box-shadow: 0 25px 50px rgba(0,0,0,0.08);
          border-color: transparent;
        }

        .modern-card:hover .accent-line {
          width: 100%;
          border-radius: 25px 25px 0 0;
        }

        .modern-card:hover .icon-container {
          background-color: #fff;
          transform: translateX(-50%) translateY(-10px) scale(1.1);
        }

        .btn-modern {
          display: inline-block;
          padding: 10px 25px;
          border-radius: 12px;
          border: 1.5px solid #eee;
          text-decoration: none;
          color: #555;
          font-weight: 700;
          font-size: 0.85rem;
          transition: 0.3s ease;
        }

        .btn-modern:hover {
          background-color: var(--hover-color);
          color: #fff !important;
          border-color: transparent;
        }

        .glass-blob {
          position: absolute;
          bottom: -20px;
          right: -20px;
          width: 100px;
          height: 100px;
          border-radius: 50%;
          filter: blur(40px);
          z-index: -1;
        }
      `}</style>
    </div>
  );
}

export default Services;
